scription": "Control on/off Zona1 inferior"}, "ElectricFence/cercos/onoff/Zona2/superior": {"zoneId": "Zona2-up", "label": "Zona2 Superior", "signal": "control", "sourceDevice": "SWITCH", "sourceInput": "I03", "description": "Control on/off Zona2 superior"}, "SWITCH/I03": {"zoneId": "Zona2-up", "label": "Zona2 Superior", "signal": "control", "sourceDevice": "SWITCH", "sourceInput": "I03", "description": "Control on/off Zona2 superior"}, "ElectricFence/cercos/onoff/Zona2/inferior": {"zoneId": "Zona2-down", "label": "Zona2 Inferior", "signal": "control", "sourceDevice": "SWITCH", "sourceInput": "I04", "description": "Control on/off Zona2 inferior"}, "SWITCH/I04": {"zoneId": "Zona2-down", "label": "Zona2 Inferior", "signal": "control", "sourceDevice": "SWITCH", "sourceInput": "I04", "description": "Control on/off Zona2 inferior"}, "ElectricFence/cercos/onoff/Zona3/superior": {"zoneId": "Zona3-up", "label": "Zona3 Superior", "signal": "control", "sourceDevice": "SWITCH", "sourceInput": "I05", "description": "Control on/off Zona3 superior"}, "SWITCH/I05": {"zoneId": "Zona3-up", "label": "Zona3 Superior", "signal": "control", "sourceDevice": "SWITCH", "sourceInput": "I05", "description": "Control on/off Zona3 superior"}, "ElectricFence/cercos/onoff/Zona3/inferior": {"zoneId": "Zona3-down", "label": "Zona3 Inferior", "signal": "control", "sourceDevice": "SWITCH", "sourceInput": "I06", "description": "Control on/off Zona3 inferior"}, "SWITCH/I06": {"zoneId": "Zona3-down", "label": "Zona3 Inferior", "signal": "control", "sourceDevice": "SWITCH", "sourceInput": "I06", "description": "Control on/off Zona3 inferior"}, "ElectricFence/cercos/onoff/Zona4/unico": {"zoneId": "Zona4", "label": "Zona4", "signal": "control", "sourceDevice": "SWITCH", "sourceInput": "I07", "description": "Control on/off Zona4"}, "SWITCH/I07": {"zoneId": "Zona4", "label": "Zona4", "signal": "control", "sourceDevice": "SWITCH", "sourceInput": "I07", "description": "Control on/off Zona4"}};
const signalLabels = { alarma: 'Alarma', estado: 'Estado', control: 'Control' };

function freshZones() {
    const zones = {};
    for (const def of zoneDefs) {
        zones[def.id] = {
            id: def.id,
            label: def.label,
            estado: false,
            alarma: false,
            control: false,
            monitored: false,
            lastSource: '',
            lastSignal: '',
            lastUpdate: '',
        };
    }
    return zones;
}

function applyArmedState(zones, armed) {
    for (const zone of Object.values(zones)) {
        zone.estado = armed;
        zone.monitored = armed;
        zone.alarma = false;
        zone.control = false;
        zone.lastSignal = armed ? 'estado' : '';
        zone.lastUpdate = new Date().toISOString();
    }
}

function clearZones(zones) {
    for (const zone of Object.values(zones)) {
        zone.estado = false;
        zone.monitored = false;
        zone.alarma = false;
        zone.control = false;
        zone.lastSource = '';
        zone.lastSignal = '';
        zone.lastUpdate = '';
    }
}

function parsePayload(payload) {
    if (typeof payload === 'string') {
        try {
            payload = JSON.parse(payload);
        } catch (err) {
            const value = payload.trim().toLowerCase();
            if (['1', 'on', 'true', 'high', 'active'].includes(value)) {
                return { active: true };
            }
            if (['0', 'off', 'false', 'low', 'inactive'].includes(value)) {
                return { active: false };
            }
            return { active: false };
        }
    }

    if (payload && typeof payload === 'object') {
        if (payload.active !== undefined) {
            return { active: !!payload.active };
        }
        if (payload.value !== undefined) {
            return { active: !!payload.value };
        }
    }

    return { active: !!payload };
}

let state = context.get('dashboardState');
if (!state) {
    const zones = freshZones();
    applyArmedState(zones, true);
    state = {
        armed: true,
        zones,
        lastEvent: {
            text: 'Sistema armado y monitoreo activo.',
            topic: '',
            source: 'dashboard',
        },
    };
}

if (msg.topic === 'dashboard/control') {
    const action = String(msg.payload || '').toLowerCase();
    if (action === 'armar') {
        state.armed = true;
        applyArmedState(state.zones, true);
        state.lastEvent = {
            text: 'Alarma armada. El monitoreo quedo encendido en todos los cercos.',
            topic: msg.topic,
            source: 'dashboard',
        };
    } else if (action === 'desarmar') {
        state.armed = false;
        clearZones(state.zones);
        state.lastEvent = {
            text: 'Sistema desalarmado. Todo el tablero quedo apagado.',
            topic: msg.topic,
            source: 'dashboard',
        };
    }
} else {
    const meta = routeMetaByTopic[msg.topic];
    if (meta) {
        const parsed = parsePayload(msg.payload);
        const active = !!parsed.active;
        const zone = state.zones[meta.zoneId];
        const source = `${meta.sourceDevice}/${meta.sourceInput}`;

        zone.lastSource = source;
        zone.lastSignal = meta.signal;
        zone.lastUpdate = new Date().toISOString();

        if (state.armed) {
            zone.monitored = true;
            if (meta.signal === 'estado') {
                zone.estado = active;
            } else if (meta.signal === 'control') {
                zone.control = active;
            } else if (meta.signal === 'alarma') {
                zone.alarma = active;
            }
        }

        let verb = active ? 'encendido' : 'apagado';
        if (meta.signal === 'alarma') {
            verb = active ? 'detectada' : 'normalizada';
        }
        state.lastEvent = {
            text: `${meta.label}: ${signalLabels[meta.signal]} ${verb}${state.armed ? '' : ' (sistema desarmado)'}`,
            topic: msg.topic,
            source,
        };
    }
}

context.set('dashboardState', state);

const zones = zoneDefs.map((def) => state.zones[def.id]);
const activeAlarmCount = zones.filter((zone) => zone.alarma).length;
const activeStatusCount = zones.filter((zone) => zone.estado).length;
const activeControlCount = zones.filter((zone) => zone.control).length;

return {
    payload: {
        armed: state.armed,
        generalState: state.armed ? 'Encendido' : 'Apagado',
        activeAlarmCount,
        activeStatusCount,
        activeControlCount,
        lastEvent: state.lastEvent,
        updatedAt: new Date().toISOString(),
        zones,
    },
};
